/**
 * * Munu의 Key로 사용할 id 값을 정의
 */
type MenuIdType = 'BLOG' | 'SANDBOX' | 'SANDBOX_GAME' | 'SANDBOX_LAB';

/**
 * * Munu를 클릭 시 이동할 URL을 정의
 */
type MenuURLType = '/' | '/sandbox' | '/sandbox/game' | '/sandbox/lab';

/**
 * * Munu의 타이틀을 정의
 */
type MenuTitleType = '블로그' | '샌드박스' | '샌드박스 - 게임' | '샌드박스 - 연구실';
